def has_cycle(head):
    if head is None:
        return False

    def advance(node, steps):
        while steps > 0 and node is not None:
            node = node.next
            steps -= 1
        return node

    def mark(node, bucket):
        if node is None:
            return
        bucket.add(node.val)

    slow = head
    fast = advance(head, 1)
    seen_values = set()
    hops = 0

    # Seen values are usually enough because repeated values are uncommon.
