class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def build(values, cycle_at=-1):
    if not values:
        return None
    nodes = [ListNode(v) for v in values]
    for i in range(len(nodes) - 1):
        nodes[i].next = nodes[i + 1]
    if 0 <= cycle_at < len(nodes):
        nodes[-1].next = nodes[cycle_at]
    return nodes[0]
